// Parse GitHub Event
const body = $input.first().json.body;
const headers = $input.first().json.headers;

const eventType = headers['x-github-event'];
const deliveryId = headers['x-github-delivery'];

let stage = 'unknown';
let branch = '';
let prTarget = '';
let commitSha = '';

if (eventType === 'push') {
  branch = body.ref.replace('refs/heads/', '');
  commitSha = body.after;
  stage = 'stage_1_push';
} else if (eventType === 'pull_request') {
  branch = body.pull_request.head.ref;
  prTarget = body.pull_request.base.ref;
  commitSha = body.pull_request.head.sha;
  if (prTarget === 'main') {
    stage = 'stage_2_pr';
  }
} else if (eventType === 'release') {
  branch = 'main';
  commitSha = body.release.tag_name;
  stage = 'stage_3_release';
}

return [{
  json: {
    eventType,
    deliveryId,
    stage,
    branch,
    prTarget,
    commitSha,
    repository: body.repository?.full_name || 'iamthamanic/easyploy',
    sender: body.sender?.login || 'unknown'
  }
}];

// Stage 1: Push Checks (2-3 Min)
const checks = [
  { name: 'install', command: 'pnpm install', weight: 10 },
  { name: 'typescript', command: 'pnpm run lint', weight: 20 },
  { name: 'eslint', command: 'pnpm eslint . --ext .ts,.tsx', weight: 20 },
  { name: 'prettier', command: 'pnpm prettier --check "**/*.{ts,tsx,json,md}"', weight: 15 },
  { name: 'npm-audit', command: 'npm audit --audit-level=moderate', weight: 15 },
  { name: 'complexity', command: 'npx complexity-report src/ || true', weight: 10 },
  { name: 'ai-review-quick', command: 'ai-review --stage=quick', weight: 10 }
];

return [{
  json: {
    stage: 'stage_1_push',
    checks,
    timeout: '5m',
    minScore: 85
  }
}];

// Stage 2: PR Checks (5-8 Min)
const checks = [
  { name: 'install', command: 'pnpm install', weight: 5 },
  { name: 'typescript', command: 'pnpm run lint', weight: 15 },
  { name: 'eslint', command: 'pnpm eslint . --ext .ts,.tsx', weight: 15 },
  { name: 'prettier', command: 'pnpm prettier --check "**/*.{ts,tsx,json,md}"', weight: 10 },
  { name: 'npm-audit', command: 'npm audit --audit-level=moderate', weight: 10 },
  { name: 'complexity', command: 'npx complexity-report src/ || true', weight: 5 },
  { name: 'sast', command: 'semgrep --config=p/typescript --error', weight: 15 },
  { name: 'architecture', command: 'shimwrappercheck --checks=solid,kiss,dry', weight: 15 },
  { name: 'update-readme', command: 'check-readme-version-sync', weight: 5 },
  { name: 'ai-review-full', command: 'ai-review --stage=full', weight: 5 }
];

return [{
  json: {
    stage: 'stage_2_pr',
    checks,
    timeout: '10m',
    minScore: 90
  }
}];

// Stage 3: Release Checks (15-30 Min)
const checks = [
  { name: 'install', command: 'pnpm install', weight: 3 },
  { name: 'typescript', command: 'pnpm run lint', weight: 10 },
  { name: 'eslint', command: 'pnpm eslint . --ext .ts,.tsx', weight: 10 },
  { name: 'prettier', command: 'pnpm prettier --check "**/*.{ts,tsx,json,md}"', weight: 5 },
  { name: 'npm-audit', command: 'npm audit --audit-level=moderate', weight: 10 },
  { name: 'complexity', command: 'npx complexity-report src/ || true', weight: 3 },
  { name: 'sast', command: 'semgrep --config=p/typescript --error', weight: 10 },
  { name: 'architecture', command: 'shimwrappercheck --checks=solid,kiss,dry', weight: 10 },
  { name: 'update-readme', command: 'check-readme-version-sync', weight: 3 },
  { name: 'unit-tests', command: 'pnpm test', weight: 15 },
  { name: 'e2e-tests', command: 'pnpm test:e2e', weight: 15 },
  { name: 'mutation-tests', command: 'stryker run', weight: 10 },
  { name: 'ai-review-full', command: 'ai-review --stage=full', weight: 6 }
];

return [{
  json: {
    stage: 'stage_3_release',
    checks,
    timeout: '45m',
    minScore: 95
  }
}];

// Calculate Score
const results = $input.all()[0].json;
const config = $input.all()[1].json;

let totalScore = 100;
const deductions = [];

// Parse check results
for (const check of config.checks) {
  const result = results[check.name];
  if (!result || result.status === 'failed') {
    totalScore -= check.weight;
    deductions.push({
      check: check.name,
      points: check.weight,
      reason: result?.error || 'Check failed'
    });
}

const passed = totalScore >= config.minScore;

return [{
  json: {
    score: totalScore,
    minScore: config.minScore,
    passed,
    deductions,
    verdict: passed ? 'ACCEPT' : 'REJECT'
  }
}];
